        var maskedConnectionString = MaskConnectionString(connectionString);
        log.LogInformation($"Database Connection: {maskedConnectionString}");

        string query = "SELECT UserId, UserName, Email FROM Users WHERE UserId = @UserId";
        
        var parameters = new Dictionary<string, object>
        {
            { "@UserId", requestDetails.UserId ?? "1" }
        };

        LogDatabaseQuerySecurely(query, parameters, log);

        try
        {
            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                log.LogInformation("Database connection opened successfully");

                using (var command = new SqlCommand(query, connection))
                {
                    foreach (var param in parameters)
                    {
                        command.Parameters.AddWithValue(param.Key, param.Value ?? DBNull.Value);
                    }

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        var results = new List<Dictionary<string, object>>();
                        
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row[reader.GetName(i)] = reader.GetValue(i);
                            }
                            results.Add(row);
                        }

                        var maskedResults = MaskDatabaseResults(results);
                        log.LogInformation($"Database query returned {results.Count} rows");
                        log.LogDebug($"Query results: {JsonConvert.SerializeObject(maskedResults)}");

                        return results;
                    }
                }
            }
        }
        catch (SqlException sqlEx)
        {
            log.LogError($"Database error occurred. Error Number: {sqlEx.Number}, State: {sqlEx.State}");
            log.LogError($"SQL Exception Message: {sqlEx.Message}");
            log.LogError($"Stack Trace: {sqlEx.StackTrace}");
            throw;
        }
    }

