                log.LogError($"  {key}: {ex.Data[key]}");
            }
        }

        if (ex.InnerException != null)
        {
            log.LogError("=== INNER EXCEPTION ===");
            LogExceptionSecurely(ex.InnerException, log);
        }

        log.LogError("=== END EXCEPTION ===");
    }

    private static string MaskSensitiveData(string data)
    {
        if (string.IsNullOrEmpty(data))
            return data;

        var sensitivePatterns = new Dictionary<string, string>
        {
            { @"password=([^&]+)", "password=[REDACTED]" },
            { @"token=([^&]+)", "token=[REDACTED]" },
            { @"apikey=([^&]+)", "apikey=[REDACTED]" },
            { @"ssn=([^&]+)", "ssn=[REDACTED]" },
            { @"creditcard=([^&]+)", "creditcard=[REDACTED]" }
        };

        string maskedData = data;
        foreach (var pattern in sensitivePatterns)
        {
            maskedData = System.Text.RegularExpressions.Regex.Replace(
                maskedData, 
                pattern.Key, 
                pattern.Value, 
                System.Text.RegularExpressions.RegexOptions.IgnoreCase
            );
        }

        return maskedData;
    }

    private static string MaskSensitiveDataInJson(string jsonData)
    {
        try
        {
            var obj = JsonConvert.DeserializeObject<Dictionary<string, object>>(jsonData);
            var sensitiveKeys = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "password", "token", "apiKey", "secret", "ssn", "creditCard", 
                "authToken", "accessToken", "refreshToken"
            };

            foreach (var key in obj.Keys.ToList())
            {
                if (sensitiveKeys.Contains(key))
                {
                    obj[key] = "[REDACTED]";
                }
            }

            return JsonConvert.SerializeObject(obj);
        }
        catch
        {
            return MaskSensitiveData(jsonData);
        }
    }

    private static string MaskUserId(string userId)
    {
        if (string.IsNullOrEmpty(userId) || userId.Length <= 4)
            return "[MASKED]";

        return userId.Substring(0, 2) + "***" + userId.Substring(userId.Length - 2);
    }

    private static string MaskConnectionString(string connectionString)
    {
        return System.Text.RegularExpressions.Regex.Replace(
            connectionString,
            @"(Password|Pwd|User Id|UID)=([^;]+)",
            "$1=[REDACTED]",
            System.Text.RegularExpressions.RegexOptions.IgnoreCase
        );
    }

    private static List<Dictionary<string, object>> MaskDatabaseResults(List<Dictionary<string, object>> results)
    {
        var maskedResults = new List<Dictionary<string, object>>();
        var sensitiveColumns = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "Email", "SSN", "CreditCard", "Password", "Token"
